import { Component, Prop, Host, h, Fragment } from '@stencil/core';

@Component({
  tag: "kds-favorite",
  styleUrl: "./kds-favorite.css",
  shadow: false
})
export class KdsFavorite {
  /** Determines whether the component is favorited. */
  @Prop() readonly favorited: boolean = false;
  /** Name of the item/coupon/recipe/whatever thing is being favorited.
   * Incorporated into informative output (aria-label) for screen reader users.
   * Eg: `what="Kroger Cereal"` will be read as "Save Kroger Cereal to my favorites."
   * or "Remove Kroger Cereal from my favorites" depending on the value of "favorite".
   * You can also choose to pass in a custom `aria-label` for full control of the read out. */
  @Prop() readonly what!: string;
  /** Disables if present. */
  @Prop() readonly disabled: boolean = false;
  /** Sets class(es) on the button. */
  @Prop() readonly buttonClass: string;

  private buttonRef: HTMLButtonElement;

  render() {
    const { favorited, what, disabled, buttonClass } = this;
    const theme = document.documentElement.getAttribute("kds-theme");

    return (
      <Host>
        <button
          aria-label={`${favorited ? "Remove" : "Save"} ${what} ${
            favorited ? "from" : "to"
          } my favorites.`}
          aria-pressed={`${Boolean(favorited)}`}
          ref={(el) => (this.buttonRef = el)}
          onClick={() =>
            this.buttonRef.setAttribute(
              "aria-pressed",
              `${!Boolean(favorited)}`
            )
          }
          class={{
            "kds-Favorite": true,
            "kds-Favorite--favorited": favorited,
            interactive: true,
            "palette-informative": true,
            "variant-border": true,
            "kind-prominent": true,
            [buttonClass]: Boolean(buttonClass)
          }}
          disabled={disabled}
        >
          {theme === "admin" ? (
            <Fragment>
              <kds-icon-ratings-solid
                class='kds-Favorite-icon'
                hidden={!favorited}
              />
              <kds-icon-ratings class='kds-Favorite-icon' hidden={favorited} />
            </Fragment>
          ) : (
            <Fragment>
              <kds-icon-favorite-solid
                class='kds-Favorite-icon'
                hidden={!favorited}
              />
              <kds-icon-favorite class='kds-Favorite-icon' hidden={favorited} />
            </Fragment>
          )}
        </button>
      </Host>
    );
  }
}
